module.exports = function(RED) {
    "use strict";

    function NeuralNeuronNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node.neurons = n.neurons || 4;
        node.activation = n.activation || "none";

        node.weights = n.weights || null;
        node.biases = n.biases || null;
        node.inputSize = n.inputSize || 3;

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            var inSize = input.length;
            if (inSize !== node.inputSize) {
                node.weights = null;
                node.biases = null;
                node.inputSize = inSize;
            }

            if (!node.weights) {
                node.weights = [];
                node.biases = [];
                for (var i = 0; i < node.neurons; i++) {
                    node.weights[i] = [];
                    for (var j = 0; j < inSize; j++) {
                        node.weights[i][j] = Math.random() * 2 - 1;
                    }
                    node.biases[i] = Math.random() * 0.4 - 0.2;
                }
            }

            var output = [];
            for (var i = 0; i < node.neurons; i++) {
                var sum = node.biases[i];
                for (var j = 0; j < inSize; j++) {
                    sum += node.weights[i][j] * (input[j] || 0);
                }
                if (node.activation === "relu") {
                    sum = Math.max(0, sum);
                } else if (node.activation === "sigmoid") {
                    sum = 1 / (1 + Math.exp(-sum));
                } else if (node.activation === "tanh") {
                    sum = Math.tanh(sum);
                }
                output.push(sum);
            }

            msg.payload = output;
            msg.neural = msg.neural || {};
            msg.neural.type = "dense";
            msg.neural.shape = [output.length];
            msg.neural.weights = node.weights;
            msg.neural.biases = node.biases;

            var active = output.filter(function(v) { return v > 0; }).length;
            node.status({ fill: active > 0 ? "blue" : "grey", shape: "dot", text: node.neurons + "n | " + output.map(function(v) { return v.toFixed(2); }).join(", ") });

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-neuron", NeuralNeuronNode);
};
